-- [ ObfusPro+ ]
local swrXU = bit32 or bit or error("ObfusPro+: Environment error");
local function kuLmPc(JNpUs)
    local bztGlIzr = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local qOxKz = string.gsub(JNpUs, '[^' .. bztGlIzr .. ']', '')
    local nEyhjea = {}
    for wKDu = 1, #qOxKz, 4 do
        local Dsp, QcY, avj, JCE = string.byte(qOxKz, wKDu, wKDu + 3)
        if not Dsp then break end
        local SeFY = string.find(bztGlIzr, string.char(Dsp)) - 1
        local PuVS = string.find(bztGlIzr, string.char(QcY)) - 1
        local pKeI = avj and string.find(bztGlIzr, string.char(avj)) - 1 or 0
        local hBia = JCE and string.find(bztGlIzr, string.char(JCE)) - 1 or 0
        local ASMB = SeFY * 262144 + PuVS * 4096 + pKeI * 64 + hBia
        local ohAu = swrXU.band(swrXU.rshift(ASMB, 16), 255)
        table.insert(nEyhjea, string.char(swrXU.bxor(ohAu, 37)))
        if avj and string.char(avj) ~= '=' then
            ohAu = swrXU.band(swrXU.rshift(ASMB, 8), 255)
            table.insert(nEyhjea, string.char(swrXU.bxor(ohAu, 37)))
        end
        if JCE and string.char(JCE) ~= '=' then
            ohAu = swrXU.band(ASMB, 255)
            table.insert(nEyhjea, string.char(swrXU.bxor(ohAu, 37)))
        end
    end
    return table.concat(nEyhjea)
end
local dkiCvD = math.sin(456);
local TFhcwEXw = [===[]===]
local aRhPJvu = kuLmPc(TFhcwEXw)
local PIFOzF = math.sin(412);
